RespawnConfig = {}
RespawnConfig.respawns = {}
RespawnConfig.bluePos = {}
RespawnConfig.redPos = {}

function RespawnConfig:init(respawns)
    self:initRespawn(respawns)
end

function RespawnConfig:initRespawn(respawns)
    for _, respawn in pairs(respawns) do
        local item = {}
        item.id = respawn.id
        item.teamId = tonumber(respawn.teamId)
        item.areaId = tonumber(respawn.areaId) or 0
        item.position = VectorUtil.newVector3(respawn.x, respawn.y, respawn.z)
        item.yaw = tonumber(respawn.yaw)
        if item.teamId == TeamManager.Blue then
            table.insert(self.bluePos, item)
        elseif item.teamId == TeamManager.Red then
            table.insert(self.redPos, item)
        else
            table.insert(self.respawns, item)
        end
    end
    if GameMatch.gameType == "g1044" then
        RespawnConfig:initRandomSeed()
    end
end
function RespawnConfig:initRandomSeed(id)
    RandomUtil:setRandomSeed()
    local data = {}
    if id == nil and #self.respawns ~= 0 then
        for index, pos in pairs(self.respawns) do
            table.insert(data, index)
        end
        RandomUtil:initRandomSeed(GameMatch.gameType, data)
        return
    end
    if id == TeamManager.Blue then
        for index, pos in pairs(self.bluePos) do
            table.insert(data, index)
        end
    else
        for index, pos in pairs(self.redPos) do
            table.insert(data, index)
        end
    end
    if #data > 0 then
        RandomUtil:initRandomSeed(GameMatch.gameType .. id, data)
    end
end

function RespawnConfig:randomRespawn(teamId)
    if teamId == nil then
        local random = RandomUtil:get(GameMatch.gameType)
        if random and random > 0 then
            return self.respawns[random]
        else
            return self.respawns[1]
        end
    end
    local random = RandomUtil:get(GameMatch.gameType .. teamId)
    if teamId == TeamManager.Blue then
        if random and random > 0 then
            return self.bluePos[random]
        else
            return self.bluePos[1]
        end
    else
        if random and random > 0 then
            return self.redPos[random]
        else
            return self.redPos[1]
        end
    end
end

function RespawnConfig:getRespawnByArea(areaId)
    local result = {}
    for _, area in pairs(self.respawns) do
        if area.areaId == areaId then
            table.insert(result, area)
        end
    end
    return result
end

function RespawnConfig:ChickenRandomRespawn(areaId)
    local pool = self:getRespawnByArea(areaId)
    if next(pool) == nil then
        return self.respawns[1]
    end

    local random = math.random(1, #pool)
    local pos = pool[random]
    return pos
end
return RespawnConfig